package com.grit.liferecorder.ui.stats
import androidx.compose.foundation.layout.*; import androidx.compose.foundation.lazy.LazyColumn; import androidx.compose.material3.*; import androidx.compose.runtime.*; import androidx.compose.ui.Modifier; import androidx.compose.ui.unit.dp; import androidx.lifecycle.compose.collectAsStateWithLifecycle
@Composable fun StatsScreen(viewModel:StatsViewModel,padding:PaddingValues){ val state by viewModel.state.collectAsStateWithLifecycle(); val s=state.summary; LazyColumn(Modifier.padding(padding).fillMaxSize(),contentPadding=PaddingValues(16.dp),verticalArrangement=Arrangement.spacedBy(12.dp)){ item{ Text("Stats",style=MaterialTheme.typography.headlineMedium); StatsTimeRangeSelector(state.range,viewModel::setRange) }; item{ StatsCard("Tasks","Created ${s.totalTasks}\nCompleted ${s.completedTasks}\nOverdue ${s.overdueTasks}\nCompletion rate ${s.taskCompletionRate}%") }; item{ StatsCard("Habit / Action Logs","Total ${s.totalLogs}\nPositive ${s.positiveLogs}\nNegative ${s.negativeLogs}\nNeutral ${s.neutralLogs}") }; item{ StatsCard("Routines","Completed ${s.routinesCompleted}\nSkipped ${s.routinesSkipped}\nMissed ${s.routinesMissed}") }; item{ StatsCard("Journal","Journal days ${s.journalDays}\nPhoto days ${s.photoJournalDays}\nNote days ${s.noteJournalDays}") } } }
@Composable fun StatsTimeRangeSelector(selected:String,onSelect:(String)->Unit){ Row(horizontalArrangement=Arrangement.spacedBy(8.dp)){ listOf("This week","This month","All time").forEach{ FilterChip(selected=selected==it,onClick={onSelect(it)},label={Text(it)}) } } }
@Composable fun StatsCard(title:String,body:String){ Card(Modifier.fillMaxWidth()){ Column(Modifier.padding(16.dp)){ Text(title,style=MaterialTheme.typography.titleMedium); Text(body,color=MaterialTheme.colorScheme.onSurfaceVariant) } } }
